use actix_web::{web, App, Error, HttpRequest, HttpResponse, HttpServer};
use reqwest;
use std::collections::HashMap;

async fn proxy_handler(req: HttpRequest) -> Result<HttpResponse, Error> {
    let query: HashMap<String, String> = req.query().into_iter().collect();
    if let Some(url) = query.get("url") {
        match reqwest::get(url).await {
            Ok(response) => {
                let body = response.text().await.unwrap_or_default();
                Ok(HttpResponse::Ok().body(body))
            }
            Err(_) => Ok(HttpResponse::BadRequest().body("Failed to fetch content")),
        }
    } else {
        Ok(HttpResponse::BadRequest().body("URL query parameter missing"))
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/proxy", web::get().to(proxy_handler))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}